text:
net batch_gate "Consume two items; verify, but do not gate, per-key batch capacity"

@arc_0: (items) -item-> [form_batch]
[form_batch] -batch-> (batches)

[form_batch] handler "form_batch"

(batches) capacityPerColorKey {"key":"batch_id","max":1}

@arc_0 weight 2

marking initial (items) <- 2 * $token_0
marking initial (batches) <- $token_1
$token_0: item {"batch_id":"A"}
$token_1: batch {"batch_id":"A"}
